/**
 * @docfonts/registry - the source of truth for docfonts evidence, plus the corpus + measurement
 * provenance schemas. Three artifact layers live in ./types; ./schema validates the public records.
 *
 * Boundary: composes parsed facts (@docfonts/font-metadata, TYPE-only) and verdicts (@docfonts/core).
 * It does NOT parse fonts or DOCX, and does NOT score - it stores results and answers queries. The
 * corpus / measurements / records live as versioned JSON under ./data. records.json is hand-curated;
 * the corpus is generated by scripts/import-corpus.ts. Query helpers here are pure and take the loaded
 * records as input.
 */

export {
  type ExportedGlyphException,
  exportSubstitutionEvidence,
  type FaceSlot,
  type SubstitutionEvidence,
  toSubstitutionEvidence,
} from "./export";
export {
  EVIDENCE_RECORDS_SCHEMA,
  type ValidateOptions,
  type ValidationResult,
  validateRecords,
} from "./schema";
export type {
  AnalyticAdvanceMeasurement,
  BakeoffCandidate,
  BakeoffRejection,
  BakeoffResult,
  BrowserCanvasMeasurement,
  CandidateFaceId,
  CandidateRef,
  CandidateScore,
  CorpusFace,
  CorpusFamily,
  CorpusId,
  CorpusManifest,
  DiscoveryFace,
  DiscoverySnapshot,
  EvidenceId,
  EvidenceRecord,
  FaceAggregateMeasurement,
  FontSource,
  Gates,
  GlyphException,
  LayoutProof,
  LiveLayoutMeasurement,
  MeasurementId,
  MeasurementKind,
  MeasurementResult,
  TopCandidatesMeasurement,
  VariableInstanceProvenance,
} from "./types";

import shipSetCorpus from "../data/corpus/current-ship-set-2026-06-03.json";
import futureDirectCandidatesCorpus from "../data/corpus/future-direct-candidates-2026-06-03.json";
import generatedInstancesCorpus from "../data/corpus/generated-instances-2026-06-03.json";
import promotedGoogleFontsCorpus from "../data/corpus/promoted-google-fonts-2026-06-05.json";
import recordsData from "../data/registry/records.json";
import substitutionEvidenceData from "../data/registry/substitution-evidence.json";
import type { SubstitutionEvidence } from "./export";
import type { CorpusManifest, EvidenceRecord } from "./types";

/**
 * The CANONICAL public registry, loaded from data/registry/records.json. That file is the hand-curated
 * source of truth (scripts/import-research.ts seeded it but is no longer authoritative - see its
 * header). Validate with validateRecords (optionally against the measurement set) before use.
 */
export function loadRecords(): EvidenceRecord[] {
  return recordsData as unknown as EvidenceRecord[];
}

/**
 * The open-font CORPUS manifests (provenance + parsed facts + hashes; no binaries). The REVIEWED tier:
 * generated by scripts/import-corpus.ts (ship-set / open-font packets) and scripts/promote-candidates.ts
 * (allow-listed promotions from the discovery snapshot, license-text-hashed). The durable join key from
 * an EvidenceRecord candidate to a corpus face is fileSha256. One manifest per source.
 */
export function loadCorpus(): CorpusManifest[] {
  return [
    shipSetCorpus as unknown as CorpusManifest,
    futureDirectCandidatesCorpus as unknown as CorpusManifest,
    generatedInstancesCorpus as unknown as CorpusManifest,
    promotedGoogleFontsCorpus as unknown as CorpusManifest,
  ];
}

/**
 * The committed renderer-facing substitution-evidence artifact (data/registry/substitution-evidence.json).
 * Generated by scripts/export-substitution-evidence.ts from loadRecords(); an export.test asserts it
 * never drifts from a fresh export. This is the public projection a renderer vendors - prose-free,
 * provenance-label-free - NOT the canonical records (loadRecords) themselves.
 */
export function loadSubstitutionEvidence(): SubstitutionEvidence[] {
  return substitutionEvidenceData as unknown as SubstitutionEvidence[];
}

/** All corpus faces across every manifest, flattened with their family. Pure. */
export function corpusFaces(manifests: readonly CorpusManifest[]) {
  return manifests.flatMap((m) =>
    m.families.flatMap((fam) =>
      fam.faces.map((face) => ({ family: fam, face })),
    ),
  );
}

/** Evidence records whose originalFont matches `name`, case-insensitive. Pure. */
export function findByOriginal(
  records: readonly EvidenceRecord[],
  name: string,
): EvidenceRecord[] {
  const key = name.toLowerCase();
  return records.filter((r) => r.originalFont.toLowerCase() === key);
}

/** Evidence records carrying a given verdict. Pure. */
export function withVerdict(
  records: readonly EvidenceRecord[],
  verdict: EvidenceRecord["verdict"],
): EvidenceRecord[] {
  return records.filter((r) => r.verdict === verdict);
}
